            {releaseIntelMessage ? (
              <p className="text-xs text-blue-900">{releaseIntelMessage}</p>
            ) : null}
          </div>

          <DialogFooter showCloseButton>
            <Button
              type="button"
              variant="secondary"
              onClick={handleApplyReleaseIntel}
              disabled={releaseIntelSaving}
