              {releaseIntelSaving ? "Applying…" : "Apply Release Intel"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog
        open={normalizeTitlesDialogOpen}
        onOpenChange={setNormalizeTitlesDialogOpen}
