                </Button>
              ) : null}
              <Button variant="ghost" size="sm" onClick={handleResetScanProgress}>
                Reset
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setShowMissingFinderDetails((prev) => !prev)}
